Implement __enter__ and __exit__ (or use contextlib.contextmanager) so the dataset can open/close resources deterministically, plus __len__/__getitem__ (map-style) or __iter__ (iterable-style). Example:

class H5Dataset:
    def __init__(self, path):
        self.path = path
        self._h5 = None
    def __enter__(self):
        import h5py
        self._h5 = h5py.File(self.path, 'r')
        self._data = self._h5['images']
        return self
    def __exit__(self, exc_type, exc, tb):
        if self._h5 is not None:
            self._h5.close()
            self._h5 = None
    def __len__(self):
        return len(self._data)
    def __getitem__(self, idx):
        return self._data[idx]

Usage:
with H5Dataset('train.h5') as ds:
    x0 = ds[0]
    # train loop...

This ensures handles close even on exceptions; it also avoids relying on __del__ which is non-deterministic.

```python
import math
from typing import Iterable

import numpy as np


def nanmean_safe(x) -> float:
    arr = np.asarray(list(x) if not isinstance(x, np.ndarray) else x, dtype=np.float64)
    if arr.size == 0:
        return float("nan")

    mask = ~np.isnan(arr)
    if not mask.any():
        return float("nan")

    # Avoid np.nanmean warnings by doing the reduction explicitly on valid values.
    return float(arr[mask].mean())
```

Edge cases: empty input and all-NaN input return NaN; explicit masking avoids NumPy warnings that `nanmean` can emit on all-NaN slices (depending on version/settings). Using float64 improves stability vs float32 for reductions.

