import ast
import operator


def eval_add_only(expr: str, env: dict):
    tree = ast.parse(expr, mode="eval")

    def walk(node):
        # Expression root
        if isinstance(node, ast.Expression):
            return walk(node.body)

        # Addition
        if isinstance(node, ast.BinOp):
            if not isinstance(node.op, ast.Add):
                raise ValueError("Only + is allowed")
            left = walk(node.left)
            right = walk(node.right)
            return operator.add(left, right)

        # Integers (Python 3.8+: ast.Constant)
        if isinstance(node, ast.Constant):
            if isinstance(node.value, int):
                return node.value
            raise ValueError("Only integer constants are allowed")

        # Names
        if isinstance(node, ast.Name):
            if node.id in env:
                val = env[node.id]
                if isinstance(val, int):
                    return val
                raise ValueError("Only integer variables are allowed")
            raise ValueError(f"Unknown variable: {node.id}")

        # Reject everything else (calls, attributes, subscripts, etc.)
        raise ValueError(f"Disallowed syntax: {type(node).__name__}")

    return walk(tree)
