from dataclasses import asdict, is_dataclass

def normalize(obj):
    # Rule 1: dataclass instance
    if is_dataclass(obj) and not isinstance(obj, type):
        return asdict(obj)

    # Rule 2: list/tuple
    if isinstance(obj, (list, tuple)):
        return [normalize(x) for x in obj]

