```python
from typing import get_origin, get_args

def matches_annotation(value, ann) -> bool:
    origin = get_origin(ann)
    args = get_args(ann)

    # Not a supported/parameterized typing annotation
    if origin is None:
        return isinstance(value, ann)

    if origin is list:
        # Expect list[T]
        if not isinstance(value, list):
            return False
        (elem_t,) = args
        return all(isinstance(x, elem_t) for x in value)

    if origin is dict:
        # Expect dict[K, V]
        if not isinstance(value, dict):
            return False
        key_t, val_t = args
        return all(isinstance(k, key_t) and isinstance(v, val_t) for k, v in value.items())

    return False
```

Explanation: This works by inspecting the *annotation object* (`ann`) using `get_origin`/`get_args`, because runtime values don’t retain generic parameters (type erasure). We can’t ask the runtime “is this a `dict[str, int]`?” directly; instead we manually validate the runtime value against the structure described by the annotation.

